Greedy insertion with best feasible assign selection based on marginal cost increase, using fallback to empty assign creation if all existing assigns fail.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    shipIdBase := total_ship
    nOrders := len(oris)

    for jj := 0; jj < nOrders; jj++ {
        ori := oris[jj]
        des := dess[jj]
        shipID := shipIdBase + jj

        var bestAssignIdx int = -1
        var bestMarginalCost float64 = 1e100
        var originalCosts [MAXASSIGNS]float64
        var originalLens [MAXASSIGNS]int

        for i := 0; i < MAXASSIGNS; i++ {
            originalCosts[i] = dispatch.Assigns[i].Cost
            originalLens[i] = dispatch.Assigns[i].StationsLen
        }

        for ii := 0; ii < dispatch.AssignsLen; ii++ {
            prevCost := dispatch.Assigns[ii].Cost
            ok := dispatch.Assigns[ii].AddShip(shipID, ori, des)
            if ok {
                dispatch.Assigns[ii].GenRoute()
                if dispatch.Assigns[ii].Cost >= 0 {
                    marginal := dispatch.Assigns[ii].Cost - prevCost
                    if marginal < bestMarginalCost {
                        bestMarginalCost = marginal
                        bestAssignIdx = ii
                    }
                }
                dispatch.Assigns[ii].RemoveShip(shipID)
                dispatch.Assigns[ii].GenRoute()
                dispatch.Assigns[ii].Cost = originalCosts[ii]
            }
        }

        if bestAssignIdx != -1 {
            dispatch.Assigns[bestAssignIdx].AddShip(shipID, ori, des)
            dispatch.Assigns[bestAssignIdx].GenRoute()
        } else {
            added := false
            for ii := dispatch.AssignsLen; ii < MAXASSIGNS; ii++ {
                ok := dispatch.Assigns[ii].AddShip(shipID, ori, des)
                if ok {
                    dispatch.Assigns[ii].GenRoute()
                    if dispatch.Assigns[ii].Cost >= 0 {
                        dispatch.AssignsLen = ii + 1
                        added = true
                        break
                    } else {
                        dispatch.Assigns[ii].RemoveShip(shipID)
                        dispatch.Assigns[ii].GenRoute()
                    }
                }
            }
            if !added {
                for ii := 0; ii < dispatch.AssignsLen; ii++ {
                    if dispatch.Assigns[ii].Cost < 0 {
                        ok := dispatch.Assigns[ii].AddShip(shipID, ori, des)
                        if ok {
                            dispatch.Assigns[ii].GenRoute()
                            if dispatch.Assigns[ii].Cost >= 0 {
                                added = true
                                break
                            } else {
                                dispatch.Assigns[ii].RemoveShip(shipID)
                                dispatch.Assigns[ii].GenRoute()
                            }
                        }
                    }
                }
                if !added {
                    targetIdx := dispatch.AssignsLen
                    if targetIdx < MAXASSIGNS {
                        ok := dispatch.Assigns[targetIdx].AddShip(shipID, ori, des)
                        if ok {
                            dispatch.Assigns[targetIdx].GenRoute()
                            dispatch.AssignsLen = targetIdx + 1
                        }
                    }
                }
            }
        }
    }

    dispatch.RenewnTotalCost()
    return dispatch

